export const meta = { name: 'check_seventeen_prime', description: 'Run two independent primality checks for 17 and synthesize surviving evidence', phases: [{ title: 'Independent Checks' }, { title: 'Synthesis' }] };

phase('Independent Checks');
const checkSpecs = [
  {
    name: 'trial-division',
    prompt: 'Independently determine whether 17 is prime using trial division. Check every relevant integer divisor through sqrt(17). Return a concise JSON object with checker, prime, and evidence.'
  },
  {
    name: 'wilson-theorem',
    prompt: 'Independently determine whether 17 is prime using Wilson’s theorem or an equivalent modular factorial calculation. Show enough concise arithmetic to support the conclusion. Return a JSON object with checker, prime, and evidence.'
  }
];
const checkSchema = {
  type: 'object',
  properties: {
    checker: { type: 'string' },
    prime: { type: 'boolean' },
    evidence: { type: 'string' }
  },
  required: ['checker', 'prime', 'evidence'],
  additionalProperties: false
};
const results = await parallel(checkSpecs.map((spec, index) => () => agent(spec.prompt, {
  label: index === 0 ? 'trial division' : 'wilson theorem',
  tier: 'small',
  schema: checkSchema
})));
const surviving = results.filter(result => result !== null);
const failedChecks = checkSpecs.filter((_, index) => results[index] === null).map(spec => spec.name);

phase('Synthesis');
const synthesis = await agent(`Synthesize the surviving independent primality-check evidence for 17. Treat the supplied failed-check list as authoritative; do not invent evidence for failed checks. Return only the requested compact object. Surviving evidence: ${JSON.stringify(surviving)}. Failed checks: ${JSON.stringify(failedChecks)}.`, {
  label: 'final synthesis',
  tier: 'big',
  schema: {
    type: 'object',
    properties: {
      prime: { type: 'boolean' },
      evidence: { type: 'array', items: { type: 'string' } },
      failedChecks: { type: 'array', items: { type: 'string' } }
    },
    required: ['prime', 'evidence', 'failedChecks'],
    additionalProperties: false
  }
});
return synthesis === null ? { prime: surviving.length > 0 && surviving.every(item => item.prime), evidence: surviving.map(item => item.evidence), failedChecks: [...failedChecks, 'final-synthesis'] } : synthesis;

